- Install `@keyv/redis` package using `$ npm install @keyv/redis`
- Register CacheModule with Redis in NestJS:
  ```typescript
  import { Module } from '@nestjs/common';
  import { CacheModule, CacheInterceptor } from '@nestjs/cache-manager';
  import { redisStore } from 'cache-manager-redis-store';

  @Module({
    imports: [
      CacheModule.register({
        store: redisStore,
        host: 'localhost',
        port: 6379,
      }),
    ],
    controllers: [],
    providers: [],
  })
  export class AppModule {}
  ```
- Use `CacheInterceptor` for caching in your services:
  ```typescript
  import { Controller, Get } from '@nestjs/common';
  import { CacheInterceptor, UseInterceptors } from '@nestjs/cache-manager';

  @Controller('example')
  @UseInterceptors(CacheInterceptor)
  export class ExampleController {
    @Get()
    getExample() {
      return 'Cached data';
    }
  }
  ```
- Ensure Redis server is running on `localhost:6379` or configure host and port accordingly.
- Check for any errors related to Redis connection or configuration in your logs.

